NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
map<string,string> f;
int n,m,k;
string s,t;
string fd(string x)
{
    if(f[x]==x) return x;
    else return f[x]=fd(f[x]);
}

void mg(string x,string y)
{
    string rx=fd(x);
    string ry=fd(y);
    if(rx!=ry)
    {
        f[rx]=ry;
    }
}
